BOJ - 2108 - 통계학문제2108번: 통계학문제 개념 산술평균 : N개의 수들의 합을 N으로 나눈 값 나눈값에 반올림 함. 중앙값 : N개의 수들을 증가하는 순서로 나열했을 경우 그 중앙에 위치하는 값 최빈값 : N개의 수들 중 가장 많이 나타나는 값 여려개일 경우 최빈값 중 2번째로 작은 값을 최빈값으로 지정 범위 : N개의 수들 중 최댓값과 최솟값의 차이구현#include &amp;lt;iostream&amp;gt;#include &amp;lt;vector&amp;gt;#include &amp;lt;algorithm&amp;gt;#include &amp;lt;math.h&amp;gt;using namespace std;int main(){ ios::sync_with_stdio(false); cin.tie(nullptr); int num, tmp; // 평균 double mean = 0; // 중앙, 최빈, 범위 int median, mode, range; vector&amp;lt;int&amp;gt; arr; vector&amp;lt;int&amp;gt; count(8001, 0); cin &amp;gt;&amp;gt; num; for(int i=0; i &amp;lt; num; i++) { cin &amp;gt;&amp;gt; tmp; arr.push_back(tmp); count[tmp + 4000] += 1; mean += tmp; } // 산술평균 mean = floor(mean/num + 0.5); // 중앙 값 sort(arr.begin(), arr.end()); median = arr[num/2]; // 범위 값 range = arr.back() - arr.front(); // 최빈값 int max = -999999; vector&amp;lt;int&amp;gt; temp; for(int i=0; i &amp;lt; count.size(); i++) if(count[i] &amp;gt; max) max = count[i]; for(int i=0; i &amp;lt; count.size(); i++) if(count[i] == max) temp.push_back(i - 4000); // 최빈값이 하나일 경우 if(temp.size() == 1) mode = temp[0]; // 여러개일 경우 // 최빈값 중 두번째로 작은 값을 최빈값으로 지정 else { sort(temp.begin(), temp.end()); temp.erase(unique(temp.begin(), temp.end()), temp.end()); mode = temp[1]; } cout &amp;lt;&amp;lt; mean &amp;lt;&amp;lt; &#39;
&#39;; cout &amp;lt;&amp;lt; median &amp;lt;&amp;lt; &#39;
&#39;; cout &amp;lt;&amp;lt; mode &amp;lt;&amp;lt; &#39;
&#39;; cout &amp;lt;&amp;lt; range &amp;lt;&amp;lt; &#39;
&#39;; return 0;}SOL 첫째 줄에 수의 개수 N(1 ≤ N ≤ 500,000)이 주어진다. 단, N은 홀수이다. 그 다음 N개의 줄에는 정수들이 주어진다. 입력되는 정수의 절댓값은 4,000을 넘지 않는다. 산술평균 요소값을 입력받음과 동시에 더한 후 N값으로 나눈다.(반올림 : std::floor 사용) // 산술평균 mean = floor(mean/num + 0.5); 중앙값 정렬 후 N/2의 인덱스 요소 값을 저장 // 중앙값 sort(arr.begin(), arr.end()); median = arr[num/2]; 범위 정렬된 배열의 첫단과 끝 단의 요소값을 뺀다. // 범위값 range = arr.back() - arr.front(); 최빈값 최빈값 즉 가장 많이 나타내는 값 max을 구한다. 최빈값을 담는 배열을 만들어 저장. 최빈값이 하나일 경우 0번째 index값 저장. 여러개일 경우 정렬 - 중복제거 - 1번째 index값 저장. int max = -999999; vector&amp;lt;int&amp;gt; temp; for(int i=0; i &amp;lt; count.size(); i++) if(count[i] &amp;gt; max) max = count[i]; for(int i=0; i &amp;lt; count.size(); i++) if(count[i] == max) temp.push_back(i - 4000); // 최빈값이 하나일 경우 if(temp.size() == 1) mode = temp[0]; // 여러개일 경우 // 최빈값 중 두번째로 작은 값을 최빈값으로 지정 else { sort(temp.begin(), temp.end()); temp.erase(unique(temp.begin(), temp.end()), temp.end()); mode = temp[1]; } 시간복잡도 O(N log N) 반올림을 구해주는 함수 floor( ) #include 선언 floor(반올림 대상 + 0.5) Reference &amp;amp; 다른 PS 모음집https://github.com/ggh-png/PSC++ STL sort ( )
